INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '10', '5.0', '10', '10', '5.0', '5.0', NULL, NULL, '2026-02-02 11:43:00', '2026');
INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '10', '5.0', '10', '10', '5.0', '5.0', NULL, NULL, '2026-02-02 11:30:00', '2026');
INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '10', '5.0', '10', '10', '5.0', '4.0', 'Venho acompanhando o Canal Solar fazem muitos anos, este é o primeiro curso que eu faço com vocês, superou minhas expectativas. Algumas observações que eu faço na plataforma online, lá poderia separar os cursos pagos pelo acessante dos curso antigos online, e cursos "free", fica meio complexo de localizar o curso específico que eu fiz, mas tem bastante material. No mais, eu entendo que é um curso complexo, e o nível dos participantes deveria ser técnico avançado ou engenheiros, vejo que tem muitos participantes que são vendedores ou pessoas que estão no business de energia solar, mas tem pouca base técnica, então o nível do curso na média é bem superior a média dos participantes, mas isto faz parte não tem como limitar isto, ok.  Gostaria de participar daquele curso presencial de armazenamento de energia que vocês já ofereceram que inclui visita a uma planta da BYD na região de Campinas. Mas a equipe está de parabéns pelo conhecimento, domínio e nível dos professores.', NULL, '2026-02-02 11:15:00', '2026');
