INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Fundamentos', '8', '5.0', '8', '8', '4.0', '4.0', NULL, NULL, '2026-03-04 15:27:41', '2026');
INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '10', '5.0', '10', '10', '5.0', '5.0', 'Sobre este curso de BESS do Canal Solar que tive a oportunidade de participar, só tenho elogios! O conteúdo foi muito bem estruturado, direto ao ponto e extremamente prático. Os instrutores dominaram bem o assunto e explicaram de forma clara até os conceitos mais complexos de armazenamento de energia. Recomendo demais para quem quer se aprofundar em baterias e sistemas de armazenamento. Parabéns à equipe do Canal Solar pela qualidade!', NULL, '2026-03-04 15:27:41', '2026');
INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '8', '5.0', '8', '6', '4.0', '3.0', 'O curso foi bom, os professores são ótimos porém referencias e/ou material auxiliar para estudo poderia melhorar muito o curso. Ex: Pdf, indicação de literaturas, aulas em laboratório etc.', NULL, '2026-03-04 15:27:41', '2026');
