INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Fundamentos', '10', '5.0', '10', '10', '5.0', '5.0', NULL, NULL, '2026-03-04 15:27:41', '2026');
INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '10', '5.0', '10', '10', '5.0', '3.0', 'Quanto aos materiais didáticos de aula (PDF) são ótimos. Porém, os materiais editáveis apresentam certeza defasagem de atualização de dados. Entendo que o que importa é o entendimento do processo, mas como o cenário muda anualmente, uma visão recente de dados poderia auxilar em maiores questionamentos. Ex: sobre projeto offgrid, os materiais de apoio são de 2017 e o 2021, onde os equipamentos nem existem mais. Outros materiais que apresentam este mesmo ponto de atenção também estão anexados ao arquivo "materiais extras". Sugiro, uma atualização de anual ou bianual para manter sempre atualizado com o cenário vivido pelos participantes do grupo.', NULL, '2026-03-04 15:27:41', '2026');
