INSERT INTO respostas_nps (nome_curso, nota_geral, nota_professores, nota_indicaria, nota_faria_outro, nota_organizacao, nota_material, feedback_positivo, feedback_negativo, data_resposta, ano) VALUES ('Armazenamento', '10', '5.0', '10', '10', '5.0', '5.0', 'Parabéns pelo alto nível dos professores e excelente material didático. A carga de matéria dada é bastante extensa e um único curso não consegue abranger todo o conhecimento necessário. Pretendo fazer outros cursos do canal.', NULL, '2026-03-03 22:18:00', '2026');
