INSERT INTO respostas_comunicacao (nome, email, empresa, avaliacao_agilidade, avaliacao_pontualidade, avaliacao_qualidade, avaliacao_beneficio, avaliacao_satisfacao, indicaria_amigo, feedback, data_resposta, ano) VALUES ('Adriele Mendes', 'adriele.mendes@clamper.com.br', 'CLAMPER', '5', '5', '5', '5', '5', '10', 'Atendimento excelente, equipe super disponível para ajudar, solucionar dúvidas e realizar as publicações dos conteúdos contratados. Estão de parabéns.', '2025-10-14 10:26:53', '2025');
INSERT INTO respostas_comunicacao (nome, email, empresa, avaliacao_agilidade, avaliacao_pontualidade, avaliacao_qualidade, avaliacao_beneficio, avaliacao_satisfacao, indicaria_amigo, feedback, data_resposta, ano) VALUES ('Johnny Santos Ludgero Oliveira', 'marketing_br@dmegc.com.cn', 'DMEGC Solar', '5', '5', '5', '5', '5', '10', 'Gostaria de registrar o apreço que tenho em trabalhar em parceria com o Canal Solar. Em especial, meu agradecimento à Cássia, que foi nossa porta de entrada e abriu caminhos importantes; à Ericka, que está sempre agilizando processos e nos apoiando em tudo que envolve os conteúdos; e ao Bruno, que desde o primeiro contato demonstrou respeito e profissionalismo, mesmo quando ainda não éramos conhecidos e que hoje se tornou um verdadeiro braço direito para nós.', '2025-10-27 09:00:17', '2025');
INSERT INTO respostas_comunicacao (nome, email, empresa, avaliacao_agilidade, avaliacao_pontualidade, avaliacao_qualidade, avaliacao_beneficio, avaliacao_satisfacao, indicaria_amigo, feedback, data_resposta, ano) VALUES ('Fernando A M CAstro', 'fcastrobr29@gmail.com', 'Flex ESS Brasil', '5', '5', '5', '5', '5', '10', 'A cada ano o evento torna-se melhor', '2025-10-23 13:23:43', '2025');
