INSERT INTO respostas_comunicacao (nome, email, empresa, avaliacao_agilidade, avaliacao_pontualidade, avaliacao_qualidade, avaliacao_beneficio, avaliacao_satisfacao, indicaria_amigo, feedback, data_resposta, ano) VALUES ('Silvio Robusti ', 'Silvio.robusti@growatt.com', 'Growatt ', '4', '4', '4', '4', '4', '10', 'Olá, anteriormente havia uma pessoa que nos lembrava das datas de envio, por e-mail e WhatsApp, além de compartilhar as publicações e enviar um resumo mensal. Isso era muito útil. Como sugestão, poderia ser disponibilizado um relatório com informações de engajamento (visualizações, cliques, comentários) das matérias, banners, entre outros conteúdos.', '2025-09-05 12:44:34', '2025');
